import{_ as t,o as i,c as s,a4 as a,a5 as o}from"./chunks/framework.BxnPb3b_.js";const u=JSON.parse('{"title":"Authorization & Headers","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/authentication.md","filePath":"introduction/authentication.md"}'),n={name:"introduction/authentication.md"};function r(l,e,h,p,d,c){return i(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="authorization-headers" tabindex="-1">Authorization &amp; Headers <a class="header-anchor" href="#authorization-headers" aria-label="Permalink to “Authorization &amp; Headers”">​</a></h1><p>To send a request to Spotify&#39;s GraphQL backend, we do not need any authentication. But to actually get a meaningful response back, we do need proper authentication.</p><div class="warning custom-block"><p class="custom-block-title">ToS Information</p><p>Spotify does <strong>not</strong> allow this, and this is the exact reason why it is against the <strong>ToS</strong>.</p><p>Spotify has their own devoted page to this to create authorized bots. See <a href="https://developer.spotify.com/" target="_blank" rel="noreferrer">Spotify Developer Home</a></p></div><p>But as you are on this page, I don&#39;t think you want to create an authorized bot.</p><h2 id="authorization-token" tabindex="-1">Authorization Token <a class="header-anchor" href="#authorization-token" aria-label="Permalink to “Authorization Token”">​</a></h2><p>Spotify uses tokens for authorization flow. There are 2 types of different tokens that Spotify utilizes. We first of all have the <code>authorization</code> token. The authorization token exists to verify that you behind the screen accessing the current account is you. It also tells the website &quot;This is an user, their request is probably legit.&quot; allowing for lesser strict limits enforced by spotify.</p><p>In short:</p><ul><li>The authorization token implies that you are authenticating as x user legitimately (or so Spotify thinks)</li></ul><h2 id="client-token" tabindex="-1">Client Token <a class="header-anchor" href="#client-token" aria-label="Permalink to “Client Token”">​</a></h2><p>The client token is a bit more complicated than the <a href="#authorization-token">Authorization Token</a>.</p><p>Listing some details about the client token below ↓</p><details class="details custom-block"><summary>Client Token Information</summary><ul><li>API requests get anonymized by the client token.</li><li>The client token prevents fraud. It also manages rate limits opposed onto your account</li><li>It&#39;s passed during the initial stages of connecting third party apps (OAuth)</li><li>Allows for grouping of telemetry and analytics data as well as crash reports originating from the same device session.</li></ul></details><h2 id="headers" tabindex="-1">Headers <a class="header-anchor" href="#headers" aria-label="Permalink to “Headers”">​</a></h2><p>Here you will learn how to combine the authorization token and the client token to fit into a single request.</p><p>Starting off with a basic python code example once again:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> requests</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">local url </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;https://api-partner.spotify.com/pathfinder/v2/query&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">local headers </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;content-type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;application/json&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">requests.post(url, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">data</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {}, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">headers</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">headers)</span></span></code></pre></div><p>Because we are not authenticated as an user, our request will return an 401 &quot;Unauthorized&quot; response. In order to make a proper request as an user we will have to pass the <code>authorization-token</code> and the <code>client-token</code> into the headers alongside the <code>content-type</code>. The <code>content-type</code> header is very important as well, because without, the server doesn&#39;t know what to respond with.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># example header structure</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">headers </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;content-type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;application/json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;authorization-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxxxxxxxxxxxxxxx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &quot;client-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xxxxxxxxxxxxxxxx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This would give us a valid response back from the server with actual response data.</p><h2 id="grabbing-your-tokens" tabindex="-1">Grabbing your tokens <a class="header-anchor" href="#grabbing-your-tokens" aria-label="Permalink to “Grabbing your tokens”">​</a></h2><p>Before you can start firing requests, you need to extract your personal tokens from your browser session. To do this, you will need to use your browser&#39;s built-in <strong>Developer Tools (DevTools)</strong>—specifically the <strong>Network</strong> tab.</p><div class="tip custom-block"><p class="custom-block-title">Developer Tools</p><p>If you&#39;ve never used DevTools before, get familiar with the <a href="https://firefox-source-docs.mozilla.org/devtools-user/" target="_blank" rel="noreferrer">Firefox DevTools Documentation</a> or the Chrome equivalents first. It&#39;ll be of advantage later on if you want to contribute.</p></div><h3 id="step-by-step-guide" tabindex="-1">Step-by-Step Guide <a class="header-anchor" href="#step-by-step-guide" aria-label="Permalink to “Step-by-Step Guide”">​</a></h3><ol><li><p>Open your browser, head over to <a href="https://open.spotify.com/" target="_blank" rel="noreferrer">Spotify Web Player</a>, and log into your account.</p></li><li><p>Press <code>F12</code> (or <code>Ctrl+Shift+I</code> / <code>Cmd+Option+I</code> on Mac) to open the DevTools, and switch to the <strong>Network</strong> tab.</p></li></ol><p><img src="`+o+'" alt="Network Tab" loading="lazy"></p><ol start="3"><li>At first, you will see a massive stream of random network garbage. To fix this, locate the <strong>Filter</strong> input field and paste the Spotify GraphQL endpoint URL:</li></ol><p><a href="https://api-partner.spotify.com/pathfinder/v2/query" target="_blank" rel="noreferrer">https://api-partner.spotify.com/pathfinder/v2/query</a></p><ol start="4"><li><p>Now, the list will only show legitimate GraphQL POST requests. Click on any of the captured requests and look at the <strong>Headers</strong> section on the right.</p></li><li><p>Scroll down to the <strong>Request Headers</strong> until you find these two specific keys:</p></li></ol><ul><li><code>authorization:</code> (Copy the entire value, including the <code>Bearer </code> prefix if present)</li><li><code>client-token:</code></li></ul><p>Simply copy both values and paste them into your Python header dictionary.</p><div class="danger custom-block"><p class="custom-block-title">TOKEN EXPIRATION</p><p>Both the <code>authorization</code> token and the <code>client-token</code> <strong>expire after exactly 1 hour</strong>. If your script suddenly starts throwing <code>401 Unauthorized</code> errors out of nowhere, you will have to refresh the Spotify tab and grab a new pair of tokens.</p></div>',31)])])}const y=t(n,[["render",r]]);export{u as __pageData,y as default};
